var e=JSON.parse(`[{"id":"L5_1","type":"dialog","speaker":null,"text":{"KOREA":"젠장! 끝도 없이 밀려온다!","JPN":"くそ！　次々と押し寄せてくる！","ENG":"Dang it! They won't stop coming!","TWN":"該死！沒完沒了！"},"stage":{"bg":"NEWTOWN","bgm":"BATTLE_NORMAL_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_BATTLEFIELD"},{"id":"L6_1","type":"dialog","speaker":null,"text":{"KOREA":"총알이 다 떨어졌어! 이대로는 모두 죽게 생겼다고!","JPN":"弾切れだ！　このままじゃみんな殺される！","ENG":"I'm out of rounds! We're all going to die at this rate!","TWN":"沒子彈了！這樣下去所有人都會死掉的！"},"stage":{"bg":"NEWTOWN","bgm":"BATTLE_NORMAL_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L10_1","type":"dialog","speaker":"TOWN_NPC_MALE_NULL","text":{"KOREA":"제이크! 뭐 하고 있어! 어서 도망쳐!","JPN":"ジェイク！　何してる！　早く逃げろ！","ENG":"Jake! What are you doing?! Get out of here!","TWN":"傑克！你在幹什麼！快點逃！"},"stage":{"bg":"NEWTOWN","bgm":"BATTLE_NORMAL_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JAKE_DELTA_CHILD_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"JAKE_DELTA_CHILD_NULL","text":{"KOREA":"시, 싫어!","JPN":"い、いやだ！","ENG":"N-no!","TWN":"不，不要！"},"stage":{"bg":"NEWTOWN","bgm":"BATTLE_NORMAL_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JAKE_DELTA_CHILD_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"JAKE_DELTA_CHILD_NULL","text":{"KOREA":"난 싸울 거야! 할아버지 몫까지 저놈들을 해치우겠어!","JPN":"俺は戦う！　じいさんの分まで奴らを倒す！","ENG":"I'm going to fight! I'll make them pay for what they've done to grandpa!","TWN":"我也要戰鬥！我要為爺爺報仇！"},"stage":{"bg":"NEWTOWN","bgm":"BATTLE_NORMAL_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JAKE_DELTA_CHILD_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"TOWN_NPC_MALE_NULL","text":{"KOREA":"투정은 그만 부려! 워커 영감님이 그런 꼴 보고 퍽이나 좋아하시겠다!","JPN":"駄々をこねてる場合じゃない！　ウォーカーじいさんがこんな姿を見て喜ぶと思うのか！","ENG":"Now's not the time for your tantrums! Your grandpa won't approve of this, you know!","TWN":"不要無理取鬧了！沃克老爺子看到一定不會高興的！"},"stage":{"bg":"NEWTOWN","bgm":"BATTLE_NORMAL_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JAKE_DELTA_CHILD_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"TOWN_NPC_MALE_NULL","text":{"KOREA":"제길, 벌써 코앞까지 들이닥쳤잖아!","JPN":"ちくしょう、もう目の前に迫ってきたぞ！","ENG":"Dang it! They're right in our faces already!","TWN":"該死，已經追上來了！"},"stage":{"bg":"NEWTOWN","bgm":"BATTLE_NORMAL_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JAKE_DELTA_CHILD_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"TOWN_NPC_MALE_NULL","text":{"KOREA":"어서 달려! 미적거리면 버리고 간다!","JPN":"さっさと走れ！　ぐずぐずすると置いていくぞ！","ENG":"Run! We'll leave any stragglers behind!","TWN":"快走！你再拖拖拉拉，我就不管你了！"},"stage":{"bg":"NEWTOWN","bgm":"BATTLE_NORMAL_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JAKE_DELTA_CHILD_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"JAKE_DELTA_CHILD_NULL","text":{"KOREA":"갈 테면 가!","JPN":"行っちまえ！","ENG":"Go if you want to run away!","TWN":"你要走就自己走！"},"stage":{"bg":"NEWTOWN","bgm":"BATTLE_NORMAL_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JAKE_DELTA_CHILD_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"JAKE_DELTA_CHILD_NULL","text":{"KOREA":"여긴 우리 마을이야! 자기가 사는 데는 자기가 지켜야 한다고 할아버지가 그랬어!","JPN":"ここは俺たちの町だ！　自分の町は自分で守るべきだとじいさんが言っていた！","ENG":"This is our village! Grandpa always said you have to protect your own home!","TWN":"這裡是我們的村莊啊！爺爺說過，自己生活的地方要由自己守護！"},"stage":{"bg":"NEWTOWN","bgm":"BATTLE_NORMAL_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JAKE_DELTA_CHILD_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"JAKE_DELTA_CHILD_NULL","text":{"KOREA":"곧 있으면 주 방위군이 올 거야! 그때까지만 버티면 되잖아?","JPN":"間もなく州の防衛軍が来るはずだ！　その時まで持てばいいんだろう？","ENG":"The National Guard will be here soon! We just have to hold out until then!","TWN":"防衛軍馬上就要來了！只要撐到那時候不就行了？"},"stage":{"bg":"NEWTOWN","bgm":"BATTLE_NORMAL_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JAKE_DELTA_CHILD_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"JAKE_DELTA_CHILD_NULL","text":{"KOREA":"왜 도망치려는 건데?!","JPN":"どうして逃げようとするんだよ！","ENG":"Why are you trying to run away?!","TWN":"為什麼要逃跑？！"},"stage":{"bg":"NEWTOWN","bgm":"BATTLE_NORMAL_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JAKE_DELTA_CHILD_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"TOWN_NPC_MALE_NULL","text":{"KOREA":"멍청한 소리 작작 해!","JPN":"寝ぼけたことを言うな！","ENG":"Don't be stupid!","TWN":"別說傻話了！"},"stage":{"bg":"NEWTOWN","bgm":"BATTLE_NORMAL_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JAKE_DELTA_CHILD_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"TOWN_NPC_MALE_NULL","text":{"KOREA":"알겠어? 우린 끝났다고! 요즘 세상에 어떤 멍청이가 이런 촌동네까지 챙겨 주냐!","JPN":"いいか？　俺たちはもうおしまいなんだよ！\\nこのご時世に、どのアホがこんな田舎町まで気にかけてくれるんだ！","ENG":"Don’t you get it? We're done for! Who'd be stupid enough to take care of a backwater place like this in this time and age?!","TWN":"懂了嗎？這裡已經完蛋了！現在這世上，怎麼可能還有笨蛋會來幫助這種小村莊啊！"},"stage":{"bg":"NEWTOWN","bgm":"BATTLE_NORMAL_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JAKE_DELTA_CHILD_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"TOWN_NPC_MALE_NULL","text":{"KOREA":"방위군은 도시 지키기에도 벅차! 그건 그냥 영감님이 상황 모르고 한 소리라고!","JPN":"防衛軍は、都市防衛だけで手一杯なんだよ！\\nじいさんが状況を知らずに言ってたことを鵜呑みにするな！","ENG":"The National Guard has their hands full with the cities as it is! Your grandpa just didn't know better!","TWN":"防衛軍光是保護城鎮就已經忙不過來了！老爺子是搞不清楚狀況，才會說出那種話啊！"},"stage":{"bg":"NEWTOWN","bgm":"BATTLE_NORMAL_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JAKE_DELTA_CHILD_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"JAKE_DELTA_CHILD_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"NEWTOWN","bgm":"BATTLE_NORMAL_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JAKE_DELTA_CHILD_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"JAKE_DELTA_CHILD_NULL","text":{"KOREA":"아냐! 분명히 군인들이 올 거야!","JPN":"いや！　必ず軍人たちが来てくれるはずだ！","ENG":"You're wrong! The soldiers will come, no matter what!","TWN":"不對！軍人們肯定會來的！"},"stage":{"bg":"NEWTOWN","bgm":"BATTLE_NORMAL_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JAKE_DELTA_CHILD_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"TOWN_NPC_MALE_NULL","text":{"KOREA":"빌어먹을, 제이크 너 설마 아직도 아저씨 일 때문에......","JPN":"くそ。ジェイク、お前まさかまだおじさんのことを引きずってて……","ENG":"Dang it, Jake! Is this about your father—","TWN":"該死，傑克你難道還在為大叔的事情……"},"stage":{"bg":"NEWTOWN","bgm":"BATTLE_NORMAL_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JAKE_DELTA_CHILD_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"TOWN_NPC_MALE_NULL","text":{"KOREA":"뭐, 뭐야? 방금 그거...... 주유소가 폭발했나?","JPN":"な、何だ？　今のは……ガソリンスタンドが爆発したのか？","ENG":"W-what was that? Did the gas station blow up?","TWN":"什，什麼？剛才那是……是加油站的爆炸聲嗎？"},"stage":{"bg":"NEWTOWN","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JAKE_DELTA_CHILD_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"JAKE_DELTA_CHILD_NULL","text":{"KOREA":"혀, 형! 저기 봐!","JPN":"あ、あれを見ろ！","ENG":"H-hey! Look over there!","TWN":"哥，哥！看那邊！"},"stage":{"bg":"NEWTOWN","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JAKE_DELTA_CHILD_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"JAKE_DELTA_CHILD_NULL","text":{"KOREA":"전차야! 전차가 오고 있어!","JPN":"戦車だ！　戦車が来てる！","ENG":"Those are tanks! We've got tanks coming!","TWN":"是戰車！戰車來了！"},"stage":{"bg":"NEWTOWN","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JAKE_DELTA_CHILD_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"TOWN_NPC_MALE_NULL","text":{"KOREA":"저, 정말이잖아...... 이런 촌동네를 도와 주러 왔다고......?","JPN":"ほ、本当だ……こんな田舎町を助けに来てくれた……？","ENG":"Y-you were right... They really came to help out a tiny village like this?","TWN":"真、真的嗎……竟然會有軍隊來幫助這種村莊……？"},"stage":{"bg":"NEWTOWN","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JAKE_DELTA_CHILD_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"DOMINIC_DELTA_NULL_NULL","text":{"KOREA":"아슬아슬하게 시간에 맞췄군요, 다행입니다.","JPN":"ギリギリ間に合いました。良かったです。","ENG":"We just barely made it. Thank goodness.","TWN":"看來勉強趕上了啊，太好了。"},"stage":{"bg":"NEWTOWN","bgm":"THEMA_SWAN_LAKE_WITHINTRO","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOMINIC_DELTA_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"DOMINIC_DELTA_NULL_NULL","text":{"KOREA":"관리국에서 지급한 새 전투복도 나쁘지 않군요.","JPN":"管理局から支給された新しい戦闘服も悪くないですね。","ENG":"The new combat fatigues from the Administration aren't bad either.","TWN":"管理局給的新戰鬥服真不錯呢。"},"stage":{"bg":"NEWTOWN","bgm":"THEMA_SWAN_LAKE_WITHINTRO","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOMINIC_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"DOMINIC_DELTA_NULL_NULL","text":{"KOREA":"2종 이하의 침식체 공격이라면 피할 필요도 없을 것 같습니다.","JPN":"第2種以下の侵食体の攻撃なら、避ける必要もなさそうです。","ENG":"I think we'll be in pretty good shape for Category 2 and below.","TWN":"好像不需要擔心2級以下的侵蝕體攻擊了。"},"stage":{"bg":"NEWTOWN","bgm":"THEMA_SWAN_LAKE_WITHINTRO","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOMINIC_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"좋은 소식이군. 하지만 우린 여기에 신형 전투복 테스트를 하러 온 게 아니야.","JPN":"それはよかった。しかし、私たちは新型戦闘服をテストしにここに来たわけではない。","ENG":"That's good to hear. But we're not here to test out the new combat uniform.","TWN":"這可真是個好消息。不過我們來這裡的目的不是為了測試新型戰鬥服。"},"stage":{"bg":"NEWTOWN","bgm":"THEMA_SWAN_LAKE_WITHINTRO","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOMINIC_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"민간인 생존자들은 어떻게 됐나?","JPN":"民間人の生存者はどうなっている？","ENG":"What happened to the civilian survivors?","TWN":"倖存者狀況如何？"},"stage":{"bg":"NEWTOWN","bgm":"THEMA_SWAN_LAKE_WITHINTRO","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOMINIC_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"DOMINIC_DELTA_NULL_NULL","text":{"KOREA":"노약자들은 방공호로 피신한 탓에 피해가 적다고 합니다.","JPN":"お年寄りや子供たちはシェルターに避難していて被害が少ないそうです。","ENG":"The elderly hunkered down in a shelter, so the damage was minimal with them.","TWN":"損失不大，年長者都躲進防空洞裡了。"},"stage":{"bg":"NEWTOWN","bgm":"THEMA_SWAN_LAKE_WITHINTRO","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOMINIC_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"DOMINIC_DELTA_NULL_NULL","text":{"KOREA":"그리고 저쪽에 있는 이들이...... 사람들을 지키고 저희가 올 때까지 버텨 준 사람들입니다.","JPN":"そして、あちらにいる者たちが……民間人を守り、我々が来るまで頑張ってくれました。","ENG":"And those folks over there... They kept everyone safe and held the ground until we arrived.","TWN":"還有那邊的人……他們保護了這裡，一直撐到我們來為止。"},"stage":{"bg":"NEWTOWN","bgm":"THEMA_SWAN_LAKE_WITHINTRO","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOMINIC_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"......우리 일을 대신해주다니, 고마운 사람들이군.","JPN":"……私たちの仕事を代わりにやってくれるとは、ありがたいな。","ENG":"So they were doing our jobs for us. I do appreciate that.","TWN":"……居然代替我們做了該做的事，真是太感謝他們了。"},"stage":{"bg":"NEWTOWN","bgm":"THEMA_SWAN_LAKE_WITHINTRO","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOMINIC_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L2_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"잠깐 인사하고 와야겠어.","JPN":"ちょっと挨拶してくる。","ENG":"I'd like to go say hello real quick.","TWN":"我得去跟他們打聲招呼才行。"},"stage":{"bg":"NEWTOWN","bgm":"THEMA_SWAN_LAKE_WITHINTRO","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOMINIC_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"TOWN_NPC_MALE_NULL","text":{"KOREA":"저 여자...... 설마 그 안토노프인가?","JPN":"あの女……まさか、あのアントノフか？","ENG":"That woman... Could she be that Antonov lady?","TWN":"那個女人……難道是安東諾夫？"},"stage":{"bg":"NEWTOWN","bgm":"THEMA_SWAN_LAKE_WITHINTRO","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JAKE_DELTA_CHILD_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"JAKE_DELTA_CHILD_NULL","text":{"KOREA":"안토노프? 그게 누군데?","JPN":"アントノフ？　誰だそれ？","ENG":"Antonov? Who's that?","TWN":"安東諾夫？那是誰？"},"stage":{"bg":"NEWTOWN","bgm":"THEMA_SWAN_LAKE_WITHINTRO","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JAKE_DELTA_CHILD_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"TOWN_NPC_MALE_NULL","text":{"KOREA":"넌 라디오도 안 듣냐? 요즘 전쟁 영웅이라고 엄청 띄워 주는 사람 있잖아.","JPN":"お前、ラジオも聴いてないのか？　最近、戦争の英雄として話題になってる人だよ。","ENG":"Don't you even listen to the radio these days? You know, the war hero everyone's been talking about.","TWN":"你都不聽廣播的嗎？最近有很多人叫她戰爭英雄，把她捧上天了啊。"},"stage":{"bg":"NEWTOWN","bgm":"THEMA_SWAN_LAKE_WITHINTRO","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JAKE_DELTA_CHILD_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"JAKE_DELTA_CHILD_NULL","text":{"KOREA":"영웅...... 저 사람이?","JPN":"英雄……あの人が？","ENG":"Hero? Her?","TWN":"英雄……那個人？"},"stage":{"bg":"NEWTOWN","bgm":"THEMA_SWAN_LAKE_WITHINTRO","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JAKE_DELTA_CHILD_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"시민 여러분.","JPN":"市民の皆さん。","ENG":"Dear citizens.","TWN":"各位市民們。"},"stage":{"bg":"NEWTOWN","bgm":"THEMA_SWAN_LAKE_WITHINTRO","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JAKE_DELTA_CHILD_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"위기에 맞서 싸운 여러분들의 용기가 있었기에 사람들의 생명을 지킬 수 있었습니다.","JPN":"危機に立ち向かってくださった皆さんの勇気があったからこそ、人々の生命を守ることができました。","ENG":"Your courage in the face of crisis has saved many lives here today.","TWN":"因為大家敢於戰鬥的勇氣，這裡的人們才得以獲救。"},"stage":{"bg":"NEWTOWN","bgm":"THEMA_SWAN_LAKE_WITHINTRO","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JAKE_DELTA_CHILD_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"군을 대신하여 감사드립니다.","JPN":"軍を代表してお礼申し上げます。","ENG":"On behalf of the military, I would like to thank you.","TWN":"我代表軍方向你們表示感謝。"},"stage":{"bg":"NEWTOWN","bgm":"THEMA_SWAN_LAKE_WITHINTRO","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JAKE_DELTA_CHILD_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"두 번 다시 이런 위험에 처하시지 않도록, 최선을 다해 전쟁을 끝내도록 하겠습니다.","JPN":"二度とこのような危険にさらされないよう、最善を尽くして戦争を終わらせます。","ENG":"The military will remain committed to ending this war as soon as possible, so that you may never have to experience such a dangerous situation again.","TWN":"為了不再次陷入這樣的危機，我會盡全力結束戰爭。"},"stage":{"bg":"NEWTOWN","bgm":"THEMA_SWAN_LAKE_WITHINTRO","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JAKE_DELTA_CHILD_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"이런, 어린 친구까지 있었구나.","JPN":"おや、幼い子供までいたのか。","ENG":"Oh, look at you. We've got ourselves a young fighter here too.","TWN":"哦，居然還有這麼小的小朋友。"},"stage":{"bg":"NEWTOWN","bgm":"THEMA_SWAN_LAKE_WITHINTRO","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JAKE_DELTA_CHILD_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"JAKE_DELTA_CHILD_NULL","text":{"KOREA":"전 어리지도 않고, 할아버지께 배워서 총은 이 마을에서 제일 잘 쏴요.","JPN":"俺は幼くないし、祖父から銃を学んだから、この町で一番射撃が上手いんです。","ENG":"I'm not young, and I'm the best shot in town. My grandpa taught me.","TWN":"我已經不小了，我和爺爺學習過槍法，所以我是這裡槍法最好的。"},"stage":{"bg":"NEWTOWN","bgm":"THEMA_SWAN_LAKE_WITHINTRO","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JAKE_DELTA_CHILD_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"JAKE_DELTA_CHILD_NULL","text":{"KOREA":"여기 있는 형이 괴물을 한 마리 잡았을 때 전 세 마리나 잡았다고요.","JPN":"ここにいる兄さんが怪物を一匹倒した時、俺は三匹も倒しました。","ENG":"I took down three monsters when this guy here only got one.","TWN":"這個小哥只幹掉了一隻怪物，我卻幹掉了三隻。"},"stage":{"bg":"NEWTOWN","bgm":"THEMA_SWAN_LAKE_WITHINTRO","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JAKE_DELTA_CHILD_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"TOWN_NPC_MALE_NULL","text":{"KOREA":"야, 누가 한 마리야! 마지막 녀석은 내가 잡았다고!","JPN":"こら、誰が一匹だ！　最後の奴は俺はやっつけたぞ！","ENG":"Hey, I got more than one! I got the last one!","TWN":"喂，誰幹掉一隻了！最後一隻明明是我解決掉的！"},"stage":{"bg":"NEWTOWN","bgm":"THEMA_SWAN_LAKE_WITHINTRO","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JAKE_DELTA_CHILD_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"그 총, 꽤 오래된 모델인데? 네 건 아닌 것 같구나.","JPN":"その銃、かなり古いモデルだが、君のものではないようだね。","ENG":"That gun you've got there's a pretty old model. I'm guessing it's not yours.","TWN":"那把槍，看起來是很久以前的型號啊？應該不是你的吧。"},"stage":{"bg":"NEWTOWN","bgm":"THEMA_SWAN_LAKE_WITHINTRO","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JAKE_DELTA_CHILD_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"JAKE_DELTA_CHILD_NULL","text":{"KOREA":"할아버지 총이에요. 젊었을 때부터 썼던 거라고 하셨어요.","JPN":"祖父の銃です。若い頃から使ってたそうです。","ENG":"It belonged to my grandpa. He said he used it since when he was young.","TWN":"這是爺爺的搶。爺爺說，他從年輕時就一直在用。"},"stage":{"bg":"NEWTOWN","bgm":"THEMA_SWAN_LAKE_WITHINTRO","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JAKE_DELTA_CHILD_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"그래? 할아버지께서는 어디 계시니?","JPN":"そうか？　おじいさんはどこに？","ENG":"Really? And where is your grandfather now?","TWN":"哦？你的爺爺現在在哪裡？"},"stage":{"bg":"NEWTOWN","bgm":"THEMA_SWAN_LAKE_WITHINTRO","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JAKE_DELTA_CHILD_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"JAKE_DELTA_CHILD_NULL","text":{"KOREA":"할아버지는......","JPN":"祖父は……","ENG":"Grandpa...","TWN":"爺爺已經……"},"stage":{"bg":"NEWTOWN","bgm":"THEMA_SWAN_LAKE_WITHINTRO","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JAKE_DELTA_CHILD_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"TOWN_NPC_MALE_NULL","text":{"KOREA":"워커 할아버지는 전투 중에 돌아가셨어요......","JPN":"ウォーカーじいさんは戦闘中に亡くなりました……","ENG":"Old Man Walker was killed in action...","TWN":"沃克爺爺在戰鬥中犧牲了……"},"stage":{"bg":"NEWTOWN","bgm":"THEMA_SWAN_LAKE_WITHINTRO","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JAKE_DELTA_CHILD_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"TOWN_NPC_MALE_NULL","text":{"KOREA":"혼란스런 와중에 그 분이 저흴 지휘하지 않았다면 이 마을에 생존자 따윈 없었을 겁니다.","JPN":"混乱の最中、彼が俺たちを仕切ってくれなかったら、この町に生存者なんていなかったはずです。","ENG":"There wouldn't be any survivors here right now if he didn't lead us through all the chaos.","TWN":"在一片混亂中，要不是有爺爺指揮我們戰鬥，這個村子就不會有倖存者了。"},"stage":{"bg":"NEWTOWN","bgm":"THEMA_SWAN_LAKE_WITHINTRO","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JAKE_DELTA_CHILD_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"그런가? 대단한 분이셨군......","JPN":"そうなのか？　素晴らしい方だったのだな……","ENG":"Is that so? It sounds like he was a great man...","TWN":"是嗎？真是個了不起的人啊……"},"stage":{"bg":"NEWTOWN","bgm":"THEMA_SWAN_LAKE_WITHINTRO","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JAKE_DELTA_CHILD_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"네 이름이 뭐지?","JPN":"君の名前は？","ENG":"What’s your name?","TWN":"你叫什麼名字？"},"stage":{"bg":"NEWTOWN","bgm":"THEMA_SWAN_LAKE_WITHINTRO","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JAKE_DELTA_CHILD_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"JAKE_DELTA_CHILD_NULL","text":{"KOREA":"그러는 누나는요?","JPN":"そういうお姉さんは？","ENG":"What about you?","TWN":"那姐姐的名字呢？"},"stage":{"bg":"NEWTOWN","bgm":"THEMA_SWAN_LAKE_WITHINTRO","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JAKE_DELTA_CHILD_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"TOWN_NPC_MALE_NULL","text":{"KOREA":"야, 야! 제이크!","JPN":"お、おい！　ジェイク！","ENG":"Hey, come on! Jake!","TWN":"喂，喂！傑克！"},"stage":{"bg":"NEWTOWN","bgm":"THEMA_SWAN_LAKE_WITHINTRO","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JAKE_DELTA_CHILD_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"후후, 당돌한 녀석인데?","JPN":"ふふっ、大胆な少年だな。","ENG":"Hah hah, I like your spirit, kid.","TWN":"呵呵，是個很有骨氣的小傢伙呢。"},"stage":{"bg":"NEWTOWN","bgm":"THEMA_SWAN_LAKE_WITHINTRO","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JAKE_DELTA_CHILD_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"내 이름은 마리아, 마리아 안토노프 대령이다.","JPN":"私の名前はマリア、マリア・アントノフ大佐だ。","ENG":"My name's Maria. Colonel Maria Antonov.","TWN":"我的名字是瑪麗亞，瑪麗亞·安東諾夫上校。"},"stage":{"bg":"NEWTOWN","bgm":"THEMA_SWAN_LAKE_WITHINTRO","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JAKE_DELTA_CHILD_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"JAKE_DELTA_CHILD_NULL","text":{"KOREA":"저, 전 제이크 워커에요.","JPN":"お、俺はジェイク・ウォーカーです。","ENG":"I-I'm Jake Walker.","TWN":"我，我叫傑克·沃克。"},"stage":{"bg":"NEWTOWN","bgm":"THEMA_SWAN_LAKE_WITHINTRO","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JAKE_DELTA_CHILD_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"그래, 제이크. 미안하다. 내가 조금만 서둘렀으면 좋았을 텐데......","JPN":"そうか。ジェイク、すまない。私がもう少し早く着いてたらよかったのに……","ENG":"Nice to meet you, Jake. And I'm sorry. I wish I could've come a bit sooner...","TWN":"是嗎，傑克。對不起。如果我能更快來到這裡……"},"stage":{"bg":"NEWTOWN","bgm":"THEMA_SWAN_LAKE_WITHINTRO","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JAKE_DELTA_CHILD_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"JAKE_DELTA_CHILD_NULL","text":{"KOREA":"그건...... 누나가 사과할 일은 아니잖아요.","JPN":"それは……お姉さんが謝ることじゃないでしょう。","ENG":"Well... You don't need to apologize for that.","TWN":"這個……姐姐不需要道歉。"},"stage":{"bg":"NEWTOWN","bgm":"THEMA_SWAN_LAKE_WITHINTRO","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JAKE_DELTA_CHILD_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"아니, 이유가 어찌됐든 시민들을 지키지 못한 건 우리의 잘못이야.","JPN":"いや、理由がどうであれ、市民を守れなかったのは私たちの責任だ。","ENG":"No, regardless of what the reason is, the military's accountable for the loss of civilian lives.","TWN":"不，不管有什麼理由，沒能保護市民就是我們的錯。"},"stage":{"bg":"NEWTOWN","bgm":"THEMA_SWAN_LAKE_WITHINTRO","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JAKE_DELTA_CHILD_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"나에겐 사과할 의무가 있다.","JPN":"だから、私には謝る義務がある。","ENG":"I am obligated to apologize.","TWN":"我有道歉的義務。"},"stage":{"bg":"NEWTOWN","bgm":"THEMA_SWAN_LAKE_WITHINTRO","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JAKE_DELTA_CHILD_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"JAKE_DELTA_CHILD_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"NEWTOWN","bgm":"THEMA_SWAN_LAKE_WITHINTRO","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JAKE_DELTA_CHILD_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"JAKE_DELTA_CHILD_NULL","text":{"KOREA":"고맙습니다, 누나. 할아버지 말씀대로 진짜 군인이라는 게 있나 봐요.","JPN":"ありがとうございます。じいさんが言ってた通り、本物の軍人が存在してたんですね。","ENG":"Thank you, ma'am. I guess grandpa was right. There really are honorable military service members out there.","TWN":"謝謝妳，姐姐。爺爺說得沒錯，世界上真的有真正的軍人呢。"},"stage":{"bg":"NEWTOWN","bgm":"THEMA_SWAN_LAKE_WITHINTRO","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JAKE_DELTA_CHILD_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"칭찬 고맙구나. 하지만 나와 함께 목숨 걸고 싸워 주는 병사들도 빼놓진 말아 주렴.","JPN":"お褒めの言葉ありがとう。だが、私と共に命をかけて戦っている兵士たちへの感謝も忘れないでほしい。","ENG":"I appreciate the compliment. But please don't forget all the other troops out there risking their lives to fight by my side.","TWN":"謝謝你的稱讚。但是不要漏掉那些與我一起並肩作戰的士兵們。"},"stage":{"bg":"NEWTOWN","bgm":"THEMA_SWAN_LAKE_WITHINTRO","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JAKE_DELTA_CHILD_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"DOMINIC_DELTA_NULL_NULL","text":{"KOREA":"대령님, 상부에서 합류 명령이 떨어졌습니다. 곧 이동하셔야 합니다.","JPN":"大佐、上層部から合流命令が下されました。そろそろ移動しなければなりません。","ENG":"Ma'am, they've issued the order to link up with the main group. We've got to get moving soon.","TWN":"上校，上級命令我們與大部隊會合。我們需要立即移動。"},"stage":{"bg":"NEWTOWN","bgm":"THEMA_SWAN_LAKE_WITHINTRO","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOMINIC_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"JAKE_DELTA_CHILD_NULL","text":{"KOREA":"......싸우러 가야 하는 거죠?","JPN":"……戦いに行くんでしょう？","ENG":"You have to go fight, don't you?","TWN":"……妳要去戰鬥了嗎？"},"stage":{"bg":"NEWTOWN","bgm":"THEMA_SWAN_LAKE_WITHINTRO","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JAKE_DELTA_CHILD_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L2_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"이기러 가야지.","JPN":"勝ちに行くのだ。","ENG":"We have to go win.","TWN":"一定會贏的。"},"stage":{"bg":"NEWTOWN","bgm":"THEMA_SWAN_LAKE_WITHINTRO","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JAKE_DELTA_CHILD_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"JAKE_DELTA_CHILD_NULL","text":{"KOREA":"전쟁...... 이길 수 있는 건가요?","JPN":"戦争……勝てますか？","ENG":"This war... Can it really be won?","TWN":"戰爭……真的能贏嗎？"},"stage":{"bg":"NEWTOWN","bgm":"THEMA_SWAN_LAKE_WITHINTRO","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JAKE_DELTA_CHILD_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"나에게 물어도 대답해 줄 수 없어. 제이크.","JPN":"私に聞いても答えられないんだ、ジェイク。","ENG":"I don't think I can answer that, Jake.","TWN":"我現在無法回答你這個問題。傑克。"},"stage":{"bg":"NEWTOWN","bgm":"THEMA_SWAN_LAKE_WITHINTRO","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JAKE_DELTA_CHILD_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"우리는 가능성을 얘기하는 사람이 아니라, 이길 방법을 찾는 사람이란다.","JPN":"私たちは可能性を語る者じゃなく、勝つ方法を探す者だ。","ENG":"We don't talk about possibilities. We find a way to win.","TWN":"我們從不討論可能性，我們只思考如何獲勝。"},"stage":{"bg":"NEWTOWN","bgm":"THEMA_SWAN_LAKE_WITHINTRO","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JAKE_DELTA_CHILD_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"JAKE_DELTA_CHILD_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"NEWTOWN","bgm":"THEMA_SWAN_LAKE_WITHINTRO","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JAKE_DELTA_CHILD_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"DOMINIC_DELTA_NULL_NULL","text":{"KOREA":"확인했습니다. 조나단 워커 상사, 전역한 지 30년이 넘은 노병이더군요.","JPN":"確認しました。ジョナサン・ウォーカー曹長、除隊して30年も経った老兵でした。","ENG":"I've got confirmation. Master Sergeant Jonathan Walker. An old veteran who's been retired for over 30 years.","TWN":"已確認。喬納森·沃克上士，據說是名已經退伍了30年的老兵。"},"stage":{"bg":"NEWTOWN","bgm":"THEMA_SWAN_LAKE_WITHINTRO","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOMINIC_DELTA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"그래, 훌륭한 군인을 잃었군.","JPN":"そうか、立派な軍人を失ったのだな。","ENG":"I see. We've lost one of the good ones.","TWN":"是嗎，我們又失去了一名優秀的軍人啊。"},"stage":{"bg":"NEWTOWN","bgm":"THEMA_SWAN_LAKE_WITHINTRO","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOMINIC_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"장례 준비는 모두 마쳤나?","JPN":"葬式の準備は済んだか？","ENG":"Are the funeral arrangements all ready to go?","TWN":"葬禮都準備好了嗎？"},"stage":{"bg":"NEWTOWN","bgm":"THEMA_SWAN_LAKE_WITHINTRO","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOMINIC_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"DOMINIC_DELTA_NULL_NULL","text":{"KOREA":"말씀하신 대로 준비했습니다. 병사들의 사기 진작에도 도움이 되겠지요.","JPN":"ご指示通り、準備を済ませております。兵士たちの士気高揚にも役立つでしょう。","ENG":"We've prepared everything as you've instructed. This should also help boost the troops' morale.","TWN":"按照您說的，都準備好了。這應該也有助於鼓舞士氣吧。"},"stage":{"bg":"NEWTOWN","bgm":"THEMA_SWAN_LAKE_WITHINTRO","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOMINIC_DELTA_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"그래. 죽은 자도 중요하지만, 살아있는 자들은 더욱 중요한 법이니까.","JPN":"そうだ。死者も大切だが、生きている者のほうがもっと大切だ。","ENG":"Yes. As important it is to honor the dead, we've got to take care of the living even more.","TWN":"好。死者固然很重要，但更重要的是活著的人。"},"stage":{"bg":"NEWTOWN","bgm":"THEMA_SWAN_LAKE_WITHINTRO","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOMINIC_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"전 부대원! 전역한 뒤에도 군인 정신을 실천하여 사람들을 지킨 워커 상사를 향해.","JPN":"全部隊員！　除隊後も軍人の精神を貫き、人々を守ったウォーカー曹長に対し、","ENG":"Attention, all troops! Today we honor Master Sergeant Walker, who laid down his life so that others may live, even long after his active duty service.","TWN":"全體隊員！向退伍後仍踐行軍人精神，保護市民們的沃克上士，"},"stage":{"bg":"NEWTOWN","bgm":"THEMA_SWAN_LAKE_WITHINTRO","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOMINIC_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"경례!","JPN":"敬礼！","ENG":"Present, arms!","TWN":"敬禮！"},"stage":{"bg":"BLACK","bgm":"THEMA_SWAN_LAKE_WITHINTRO","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_COMBAT_ALL_SMASH_ATTACK_SMALL"}]`);export{e as default};